// ── PARÁMETROS DEL MODELO ───────────────────────────────────────────────────
const SIGMA    = 150;   // Gaussiana de similitud de ranking FIFA (pts)
const HOME_ADV = 1.12;  // Ventaja de local

// ── RANKING FIFA (Jun 2026) ──────────────────────────────────────────────────
const FIFA_PTS: Record<string, number> = {
  "Argentina":1877,"España":1875,"Francia":1871,"Inglaterra":1828,
  "Portugal":1768,"Brasil":1766,"Marruecos":1755,"Países Bajos":1754,
  "Bélgica":1742,"Alemania":1736,"Croacia":1715,"Colombia":1698,
  "México":1687,"Senegal":1684,"Uruguay":1673,"EE.UU.":1671,
  "Japón":1662,"Suiza":1650,"Irán":1620,"Turquía":1606,
  "Ecuador":1599,"Austria":1597,"Corea del Sur":1592,"Australia":1579,
  "Argelia":1571,"Egipto":1562,"Canadá":1559,"Noruega":1557,
  "Costa de Marfil":1541,"Panamá":1539,"Suecia":1510,
  "Rep. Checa":1506,"Paraguay":1505,"Escocia":1503,
  "Haití":1200,"Qatar":1250,"Cabo Verde":1280,"Curaçao":1100,
  "Sudáfrica":1350,"Irak":1340,"Arabia Saudita":1360,
  "R.D. Congo":1380,"Uzbekistán":1320,"Bosnia y Herz.":1450,
  "Ghana":1460,"Túnez":1440,"Nueva Zelanda":1390,"Jordania":1370,
};

// ── FUNCIONES CORE ──────────────────────────────────────────────────────────

function simWeight(rivalPts: number, targetPts: number): number {
  const diff = rivalPts - targetPts;
  return Math.exp(-(diff * diff) / (2 * SIGMA * SIGMA));
}

function estimateLambda(team: string, rivalTarget: string, isHome: boolean): number {
  const targetPts = FIFA_PTS[rivalTarget] ?? 1150;
  let totalW = 0;
  let totalGF = 0;

  for (const [h, a, hs, as_, hPts, aPts, twDecay, neutral] of HISTORY) {
    let gf: number;
    let rivalPts: number;
    let locFactor: number;

    if (h === team) {
      gf       = hs;
      rivalPts = aPts;
      locFactor = neutral ? 1.0 : HOME_ADV;
    } else if (a === team) {
      gf       = as_;
      rivalPts = hPts;
      locFactor = neutral ? 1.0 : (1.0 / HOME_ADV);
    } else {
      continue;
    }

    const w = simWeight(rivalPts, targetPts) * twDecay;
    totalW  += w;
    totalGF += (gf / locFactor) * w;
  }

  const base = totalW > 0.05 ? totalGF / totalW : 1.2;
  return base * (isHome ? HOME_ADV : 1.0);
}

function poissonProb(lambda: number, k: number): number {
  if (k < 0 || k > 20 || lambda <= 0) return 0;
  let logP = -lambda + k * Math.log(lambda);
  for (let i = 1; i <= k; i++) logP -= Math.log(i);
  return Math.exp(logP);
}

function scoreProbability(lambdaH: number, lambdaA: number, sh: number, sa: number): number {
  return poissonProb(lambdaH, sh) * poissonProb(lambdaA, sa);
}

function mostLikelyScore(lambdaH: number, lambdaA: number): [number, number] {
  return [Math.round(lambdaH), Math.round(lambdaA)];
}

// ── RUTAS ───────────────────────────────────────────────────────────────────

// GET /probabilities?home=Argentina&away=Francia&scores=2-1,1-0,0-0&neutral=true
router.get("/probabilities", (req, res) => {
  const { home, away, scores, neutral } = req.query as {
    home: string; away: string; scores: string; neutral?: string;
  };

  if (!home || !away || !scores) {
    res.status(400).json({ error: "Missing home, away or scores params" });
    return;
  }

  const isHome = neutral !== "false";
  const lH = estimateLambda(home, away, isHome);
  const lA = estimateLambda(away, home, !isHome);

  const scoreList = scores.split(",").map((s: string) => s.trim());
  const result: Record<string, number> = {};

  for (const score of scoreList) {
    const parts = score.split("-");
    if (parts.length !== 2) continue;
    const sh = parseInt(parts[0]);
    const sa = parseInt(parts[1]);
    if (isNaN(sh) || isNaN(sa)) continue;
    result[score] = Math.round(scoreProbability(lH, lA, sh, sa) * 10000) / 100;
  }

  res.json({ home, away, probabilities: result, lambdaH: lH, lambdaA: lA });
});

// GET /prediction?home=Argentina&away=Francia&neutral=true
router.get("/prediction", (req, res) => {
  const { home, away, neutral } = req.query as {
    home: string; away: string; neutral?: string;
  };

  if (!home || !away) {
    res.status(400).json({ error: "Missing home or away params" });
    return;
  }

  const isHome = neutral !== "false";
  const lH = estimateLambda(home, away, isHome);
  const lA = estimateLambda(away, home, !isHome);
  const [predH, predA] = mostLikelyScore(lH, lA);
  const prob = scoreProbability(lH, lA, predH, predA);

  res.json({
    home, away,
    prediction: `${predH}-${predA}`,
    probability: Math.round(prob * 10000) / 100,
    lambdaH: Math.round(lH * 1000) / 1000,
    lambdaA: Math.round(lA * 1000) / 1000,
  });
});

export default router;
